use std::io;
use std::fs;

struct Guard {
    name: String,
}

impl Drop for Guard {
    fn drop(&mut self) {
        println!("--- Cleanup running automatically for {} ---n", self.name);
    }
}

fn process_data(input_file_path: &str, guard_name: &str) -> io::Result<()> {
    let _cleanup = Guard { name: guard_name.to_string() };
    println!("Starting processing for file: {}", input_file_path);

    let content = fs::read_to_string(input_file_path)?;
    if content.is_empty() {
        return Ok(());
    }

    let lines: Vec<String> = content.lines().map(String::from).collect();
    println!("Successfully read {} lines.", lines.len());

    if let Some(last_line) = lines.last() {
        println!("Processing last line: {}", last_line);
    }

    Ok(())
}

fn main() -> io::Result<()> {
    let dummy_data = "key1=valueAnkey2=valueBnkey3=finalValue";
    const INPUT_FILE: &str = "benchmark_input.txt";

    fs::write(INPUT_FILE, dummy_data)?; 

    println!("Running simulation 1 (Success Path)");
    process_data(INPUT_FILE, "Guard A")?;

    println!("n===============================n");

    println!("Running simulation 2 (End of main)");
    process_data(INPUT_FILE, "Guard B")?;

    Ok(())
}

