use std::sync::{Mutex, Arc};

struct BufferGuard { 
    name: String,
    is_active: bool
}
impl Drop for BufferGuard {
    fn drop(&mut self) {
        if self.is_active {
            println!("Automatically releasing buffer: {}", self.name);
        }
    }
}

fn process_data(shared_resources: &HashMap<String, Arc<Mutex<i32>>>) -> Result<(), Box<dyn std::error::Error>> {
    let mut guard1 = BufferGuard { name: "Temp_A".to_string(), is_active: true };
    let buffer_a_lock = shared_resources.get("Temp_A").unwrap().clone();

    { 
        println!("Entering scope for Temp_A processing.");
        let mut data_a = buffer_a_lock.lock().unwrap();
        *data_a += 10;
