use std::collections::VecDeque;

struct StackResource {
    data: VecDeque<i32>,
}

impl Drop for StackResource {
    fn drop(&mut self) {
        println!("--- Resource automatically cleaned up on scope exit ---n");
    }
}

struct VirtualMachine {
    stack: StackResource,
}

impl VirtualMachine {
    fn new() -> Self {
        VirtualMachine { 
            stack: StackResource { data: VecDeque::new() }
        }
    }

    fn push_bytecode(&mut self, value: i32) {
        self.stack.data.push_back(value);
        println!("Pushed bytecode value: {}", value);
    }

    fn execute_block(&mut self) {
        let guard = StackResource { data: VecDeque::new() };
        println!("Entering code block scope.");
        self.push_bytecode(10);
        self.push_bytecode(20);
        drop(guard); 
        println!("Exiting code block scope.");
    }
}

fn main() {
    let mut vm = VirtualMachine::new();
    vm.push_bytecode(1);
    vm.execute_block();
}

use std::collections::HashMap;
use std::sync::{Mutex, Arc};

struct SystemState {
    settings: HashMap<String, String>,
}
impl Default for SystemState {
    fn default() -> Self {
        SystemState { settings: HashMap::new() }
    }
}

struct Guard {
    state: Arc<Mutex<SystemState>>,
}
impl Drop for Guard {
    fn drop(&mut self) {
        println!("Resource cleanup guaranteed when Guard goes out of scope.");
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let state = Arc::new(Mutex::new(SystemState::default()));
    { 
        let _guard = Guard { state: Arc::clone(&state) };
        println!("Entering scope where resource is managed.");
        {
            let mut s = state.lock().unwrap();
            s.settings.insert("theme".to_string(), "dark".to_string());
            println!("Settings updated successfully within inner block.");
        }
        println!("Exiting inner scope.");
    }
    println!("Scope ended, Guard dropped and cleanup executed.");
    Ok(())
}

use std::fs::File;
use std::io::{self, Write};

struct ConnectionGuard { 
    file: File,
}

impl ConnectionGuard {
    fn new(path: &str) -> io::Result<Self> {
        Ok(ConnectionGuard { file: File::create(path)? })
    }

    fn write_data(&mut self, data: &[u8]) -> io::Result<()> {
        self.file.write(data)?;
        Ok(())
    }
}

impl Drop for ConnectionGuard {
    fn drop(&mut self) {
        println!("Resource cleanup: Successfully closed the file connection.");
    }
}

fn main() -> io::Result<()> {
    let mut guard = ConnectionGuard::new("game_state.dat")?;
    guard.write_data(&[0xDE, 0xAD, 0xBE, 0xEF])?;

